def format_full_name(first: str, last: str) -> str:
    full_name = f"{first.strip()} {last.strip()}"
    return full_name

def create_profile(name: str, city: str) -> dict:
    profile = {"name": name, "city": city}
    return profile

def describe_age(age: int) -> str:
    if age >= 18:
        return "Adult"
    return "Minor"

def sign_label(num: int) -> str:
    if num >= 0:
        return "Positive"
    return "Negative"

def grade_score(score: int) -> str:
    if score >= 90:
        return "A"
    if score >= 80:
        return "B"
    if score >= 70:
        return "C"
    return "F"

def is_even_label(num: int) -> str:
    if num % 2 == 0:
        return "Even"
    return "Odd"

def ride_clearance(height_inches: int) -> str:
    if height_inches >= 48:
        return "Ride"
    return "Grow"

def pass_fail(score: int) -> str:
    if score >= 60:
        return "Pass"
    return "Fail"

def numbers_to_five() -> list[int]:
    result = []
    for value in range(1, 6):
        result.append(value)
    return result

def countdown(start: int) -> list[int]:
    values = []
    while start > 0:
        values.append(start)
        start -= 1
    return values

def sum_list(numbers: list[int]) -> int:
    total = 0
    for num in numbers:
        total += num
    return total

def seven_times_table() -> str:
    parts = []
    for n in range(1, 11):
        parts.append(str(7 * n))
    return " ".join(parts)

def repeat_word(word: str, times: int) -> list[str]:
    copies = []
    for _ in range(times):
        copies.append(word)
    return copies

def even_numbers(limit: int) -> list[int]:
    values = []
    for number in range(0, limit + 1, 2):
        values.append(number)
    return values

def factorial(n):
    if n <= 1:
        return 1
    return n * factorial(n - 1)

def absolute_difference(a: int, b: int) -> int:
    difference = a - b
    if difference < 0:
        difference = -difference
    return difference

def append_green(colors: list[str]) -> list[str]:
    colors.append('green')
    return colors

def merge_names(primary: list[str], extras: list[str]) -> list[str]:
    combined = primary + extras
    return combined
